//! Symmetric envelope used to encrypt the on-disk secret store.
//!
//! Mirrors `secret-storage/src/crypto.ts`:
//! 1. Derive a 32-byte symmetric key from `passphrase + salt` via
//!    scrypt.
//! 2. Encrypt plaintext with AES-256-GCM under that key + a random
//!    96-bit IV; the GCM tag is captured.
//! 3. Persist `{ salt, iv, tag, ciphertext }`, all base64-encoded.
//!
//! Not wire-compatible with the JS file format (we chose a Rust-
//! idiomatic envelope vs the upstream's specific Node shape). The
//! algorithm choices are standards-defined, so individual keys
//! generated by either side can be moved between stores by re-
//! exporting / re-importing.

#![allow(dead_code)] // wired by file_secret_store next.

use aes_gcm::aead::Aead;
use aes_gcm::{Aes256Gcm, KeyInit, Nonce};
use base64::Engine;
use base64::engine::general_purpose::STANDARD as B64;
use rand::RngCore;
use scrypt::{Params as ScryptParams, scrypt};
use serde::{Deserialize, Serialize};

use crate::secret_storage::SecretStoreError;

/// scrypt parameters — matches the upstream's `node:crypto.scryptSync`
/// defaults at Node 24: N = 2^14 (16384), r = 8, p = 1. Less than
/// `scrypt-rs`'s recommended-modern-default (2^17) — the upstream's
/// default is what's actually deployed today, so we match it. Bump
/// when we revisit the file format.
const SCRYPT_LOG_N: u8 = 14;
const SCRYPT_R: u32 = 8;
const SCRYPT_P: u32 = 1;

/// Derive a 32-byte AES-256 key from `passphrase` + `salt` via
/// scrypt. `salt` is 32 bytes — matches `node:crypto.randomBytes(32)`
/// at the upstream call site.
fn derive_key(passphrase: &[u8], salt: &[u8]) -> Result<[u8; 32], SecretStoreError> {
    let params = ScryptParams::new(SCRYPT_LOG_N, SCRYPT_R, SCRYPT_P, 32)
        .map_err(|e| SecretStoreError::Crypto(format!("scrypt params: {e}")))?;
    let mut out = [0u8; 32];
    scrypt(passphrase, salt, &params, &mut out)
        .map_err(|e| SecretStoreError::Crypto(format!("scrypt: {e}")))?;
    Ok(out)
}

/// Serializable AES-256-GCM envelope. Field names + base64 (not
/// base64url) encoding match the upstream `EncryptedPayload`.
#[derive(Clone, Debug, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "camelCase")]
pub(crate) struct EncryptedPayload {
    pub salt: String,
    pub iv: String,
    /// AES-GCM doesn't separate ciphertext + tag in this crate;
    /// kept as a named field for upstream parity. Always 16 bytes.
    pub tag: String,
    pub ciphertext: String,
}

/// Encrypt `plaintext` under a passphrase. Each call generates a
/// fresh random salt + IV; output is self-describing.
pub(crate) fn encrypt_json(
    passphrase: &str,
    plaintext: &[u8],
    rng: &mut (impl RngCore + rand::CryptoRng),
) -> Result<EncryptedPayload, SecretStoreError> {
    let mut salt = [0u8; 32];
    rng.fill_bytes(&mut salt);
    let mut iv = [0u8; 12]; // GCM standard 96-bit nonce
    rng.fill_bytes(&mut iv);

    let key = derive_key(passphrase.as_bytes(), &salt)?;
    let cipher = Aes256Gcm::new_from_slice(&key)
        .map_err(|e| SecretStoreError::Crypto(format!("aes key: {e}")))?;
    let ct_with_tag = cipher
        .encrypt({
            // `Nonce::from_slice` is deprecated upstream in favour of
            // `generic-array` 1.x, but `aes-gcm` 0.10 still uses 0.14
            // — the method works correctly, we just have to suppress
            // the deprecation warning until the crate releases an
            // upgrade. The borrow lives only for the call.
            #[allow(deprecated)]
            Nonce::from_slice(&iv)
        }, plaintext)
        .map_err(|e| SecretStoreError::Crypto(format!("aes encrypt: {e}")))?;

    // `aes-gcm` appends the 16-byte tag to ciphertext. Split for
    // upstream-parity. (Field order purely cosmetic — both pieces
    // ride together in the JSON envelope.)
    let split = ct_with_tag.len().saturating_sub(16);
    let (ct, tag) = ct_with_tag.split_at(split);
    Ok(EncryptedPayload {
        salt: B64.encode(salt),
        iv: B64.encode(iv),
        tag: B64.encode(tag),
        ciphertext: B64.encode(ct),
    })
}

/// Decrypt an envelope. Wrong passphrase / tampered ciphertext →
/// `SecretStoreError::Crypto`.
pub(crate) fn decrypt_json(
    passphrase: &str,
    payload: &EncryptedPayload,
) -> Result<Vec<u8>, SecretStoreError> {
    let salt = B64
        .decode(payload.salt.as_bytes())
        .map_err(|e| SecretStoreError::InvalidInput(format!("salt b64: {e}")))?;
    let iv = B64
        .decode(payload.iv.as_bytes())
        .map_err(|e| SecretStoreError::InvalidInput(format!("iv b64: {e}")))?;
    if iv.len() != 12 {
        return Err(SecretStoreError::InvalidInput(format!(
            "iv must be 12 bytes, got {}",
            iv.len()
        )));
    }
    let tag = B64
        .decode(payload.tag.as_bytes())
        .map_err(|e| SecretStoreError::InvalidInput(format!("tag b64: {e}")))?;
    if tag.len() != 16 {
        return Err(SecretStoreError::InvalidInput(format!(
            "tag must be 16 bytes, got {}",
            tag.len()
        )));
    }
    let mut ct = B64
        .decode(payload.ciphertext.as_bytes())
        .map_err(|e| SecretStoreError::InvalidInput(format!("ct b64: {e}")))?;
    ct.extend_from_slice(&tag);

    let key = derive_key(passphrase.as_bytes(), &salt)?;
    let cipher = Aes256Gcm::new_from_slice(&key)
        .map_err(|e| SecretStoreError::Crypto(format!("aes key: {e}")))?;
    cipher
        .decrypt({
            // `Nonce::from_slice` is deprecated upstream in favour of
            // `generic-array` 1.x, but `aes-gcm` 0.10 still uses 0.14
            // — the method works correctly, we just have to suppress
            // the deprecation warning until the crate releases an
            // upgrade. The borrow lives only for the call.
            #[allow(deprecated)]
            Nonce::from_slice(&iv)
        }, ct.as_slice())
        .map_err(|e| SecretStoreError::Crypto(format!("aes decrypt: {e}")))
}

#[cfg(test)]
mod tests {
    use super::*;
    use rand::SeedableRng;

    fn rng() -> rand::rngs::StdRng {
        rand::rngs::StdRng::seed_from_u64(0xfeedbeef)
    }

    #[test]
    fn round_trip_encrypt_decrypt() {
        let mut r = rng();
        let plaintext = b"the quick brown fox jumps over the lazy dog";
        let env = encrypt_json("hunter2", plaintext, &mut r).unwrap();
        let out = decrypt_json("hunter2", &env).unwrap();
        assert_eq!(out, plaintext);
    }

    #[test]
    fn wrong_passphrase_fails() {
        let mut r = rng();
        let env = encrypt_json("correct", b"secret data", &mut r).unwrap();
        let err = decrypt_json("wrong", &env).unwrap_err();
        // GCM authentication tag mismatch surfaces as Crypto.
        assert!(matches!(err, SecretStoreError::Crypto(_)));
    }

    #[test]
    fn tampered_ciphertext_fails() {
        let mut r = rng();
        let mut env = encrypt_json("p", b"hello", &mut r).unwrap();
        // Flip a base64 character in the ciphertext — easiest tamper.
        let mut ct = env.ciphertext.clone().into_bytes();
        ct[0] = if ct[0] == b'A' { b'B' } else { b'A' };
        env.ciphertext = String::from_utf8(ct).unwrap();
        // Either decode-of-corrupted-b64 (InvalidInput) or
        // authentication-tag-mismatch (Crypto) — both reject.
        let err = decrypt_json("p", &env).unwrap_err();
        assert!(matches!(
            err,
            SecretStoreError::Crypto(_) | SecretStoreError::InvalidInput(_)
        ));
    }

    #[test]
    fn envelope_round_trips_through_json() {
        let mut r = rng();
        let env = encrypt_json("pw", b"data", &mut r).unwrap();
        let s = serde_json::to_string(&env).unwrap();
        let back: EncryptedPayload = serde_json::from_str(&s).unwrap();
        assert_eq!(env, back);
        // Roundtrip through serde shouldn't change the plaintext we get.
        let out = decrypt_json("pw", &back).unwrap();
        assert_eq!(out, b"data");
    }

    #[test]
    fn each_call_uses_fresh_salt_and_iv() {
        let mut r = rng();
        let env_a = encrypt_json("pw", b"plaintext", &mut r).unwrap();
        let env_b = encrypt_json("pw", b"plaintext", &mut r).unwrap();
        // Same plaintext + same passphrase MUST produce different
        // ciphertexts (different IV + salt).
        assert_ne!(env_a.iv, env_b.iv);
        assert_ne!(env_a.salt, env_b.salt);
        assert_ne!(env_a.ciphertext, env_b.ciphertext);
    }
}
